const fs = require('fs');
const configPath = 'C:\\Users\\admin\\projects\\news-aggregator\\config\\sources.json';
const config = JSON.parse(fs.readFileSync(configPath, 'utf8'));

const enabledSources = config.sources.filter(s => s.enabled);

return enabledSources.map(source => ({
  json: source
}));

const source = items[0].json;
const rss = items[0].json.rss?.channel?.[0];

if (!rss || !rss.item) {
  return [];
}

const articles = rss.item.slice(0, 10);

const results = articles.map((article, index) => {
  const title = Array.isArray(article.title) ? article.title[0] : article.title;
  const link = Array.isArray(article.link) ? article.link[0] : article.link;
  const description = Array.isArray(article.description) ? article.description[0] : article.description;
  const pubDate = Array.isArray(article.pubDate) ? article.pubDate[0] : article.pubDate;

  return {
    json: {
      id: `${source.name.toLowerCase().replace(/\s+/g, '-')}-${Date.now()}-${index}`,
      title: title || '',
      link: link || '',
      description: (description || '').replace(/<[^>]*>/g, ''),
      source: source.name,
      category: source.category,
      pubDate: new Date(pubDate).toLocaleString('vi-VN', {
        timeZone: 'Asia/Ho_Chi_Minh',
        day: '2-digit',
        month: '2-digit',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
      }),
      collectedAt: new Date().toLocaleString('vi-VN', {
        timeZone: 'Asia/Ho_Chi_Minh',
        day: '2-digit',
        month: '2-digit',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
      })
    }
  };
});

return results;

const fs = require('fs');
const configPath = 'C:\\Users\\admin\\projects\\news-aggregator\\config\\keywords.json';
const config = JSON.parse(fs.readFileSync(configPath, 'utf8'));

const includeKeywords = config.keywords.include.map(k => k.toLowerCase());
const excludeKeywords = config.keywords.exclude.map(k => k.toLowerCase());

const filtered = items.filter(item => {
  const text = (item.json.title + ' ' + item.json.description).toLowerCase();

  const hasExclude = excludeKeywords.some(keyword => text.includes(keyword));
  if (hasExclude) return false;

  const hasInclude = includeKeywords.some(keyword => text.includes(keyword));
  return hasInclude;
});

return filtered;

const fs = require('fs');
const path = require('path');

const today = new Date().toISOString().split('T')[0];
const dataDir = 'C:\\Users\\admin\\projects\\news-aggregator\\data\\news';
const filePath = path.join(dataDir, `${today}.json`);

let existingData = [];
if (fs.existsSync(filePath)) {
  existingData = JSON.parse(fs.readFileSync(filePath, 'utf8'));
}

const newArticles = items.map(item => item.json);
const existingIds = existingData.map(a => a.id);
const uniqueArticles = newArticles.filter(a => !existingIds.includes(a.id));

const allArticles = [...existingData, ...uniqueArticles];
fs.writeFileSync(filePath, JSON.stringify(allArticles, null, 2), 'utf8');

return [{
  json: {
    message: `Đã lưu ${uniqueArticles.length} tin mới`,
    total: allArticles.length,
    file: filePath,
    timestamp: new Date().toLocaleString('vi-VN', {
      timeZone: 'Asia/Ho_Chi_Minh'
    })
  }
}];
